'{"current_value": 7.2, "target_value": 5.0, "unit": "%", "formula": "(Rider Cancellations / Total Requests) × 100", "tracking_frequency": "Real-time", "data_source": "Ride Records", "thresholds": {"red": ">10%", "yellow": "5-10%", "green": "<5%"}, "cancellation_reasons": {"long_wait": 45, "price": 25, "changed_plans": 15, "driver_concerns": 10, "other": 5}, "cancellation_fee": "$5 after 2min", "owner": "VP Product"}'::jsonb,
