'ACTIVE', 1,
'{"current_value": 75000000, "target_value": 100000000, "unit": "$ monthly", "formula": "Sum(all ride charges)", "tracking_frequency": "Real-time", "data_source": "Payments DB", "annual_current": 900000000, "annual_target": 1200000000, "yoy_growth": 25, "take_rate": 25, "gmv_per_rider": 360, "owner": "CFO"}'::jsonb,
