'ACTIVE', 1,
'{"current_value": 25.0, "target_value": 26.0, "unit": "%", "formula": "(Platform Revenue / GMV) × 100", "tracking_frequency": "Daily", "data_source": "Financial Analytics", "breakdown": {"base_commission": 20, "service_fee": 3, "booking_fee": 2, "surge": 2}, "by_service": {"standard": 24, "premium": 30, "subscription": 18, "enterprise": 22}, "owner": "CFO"}'::jsonb,
