'ACTIVE', 1,
'{"current_value": 38.0, "target_value": 45.0, "unit": "%", "formula": "(Revenue - Variable Costs) / Revenue × 100", "tracking_frequency": "Real-time", "data_source": "Financial Analytics", "cost_breakdown": {"driver_payout": 75, "payment_processing": 2.5, "insurance": 3, "other": 1.5}, "by_tier": {"standard": 38, "premium": 52, "subscription": 28}, "owner": "CFO"}'::jsonb,
