'ACTIVE', 1,
'{"current_value": 4.5, "target_value": 3.0, "unit": "minutes", "formula": "AVG(arrival_time - request_time)", "tracking_frequency": "Real-time", "data_source": "Matching System", "thresholds": {"red": ">6min", "yellow": "4-6min", "green": "<4min"}, "by_area": {"urban": 3.2, "suburban": 5.8, "rural": 8.5}, "by_time": {"peak": 5.2, "off_peak": 3.8}, "nps_correlation": 0.85, "owner": "VP Operations"}'::jsonb,
